import React, { Component } from 'react';
import Spinner from 'react-bootstrap/Spinner';
export class AddressSearch extends Component {
  constructor(props) {
    super(props);
    let coord2regioncode = { x: '127.1086228', y: '37.4012191', data: [], loading: true };
    this.state = { query: '전북 삼성동 100', data: [], loading: true 
      , coord2regioncode: coord2regioncode
    };
    
  }

  componentDidMount() {
    this.populateWeatherData(this.state.query);
    this.renderCoord2regioncode(this.state.coord2regioncode.x, this.state.coord2regioncode.y);
  }

  static renderForecastsTable(documents) {
    return (
      <table className='table table-striped' aria-labelledby="tabelLabel">
        <tbody>
          {documents.map(document =>
            <tr>
              <td>
                <p>{document.address.address_name}</p>
                <p>x: {document.x} / y: {document.y}</p>
              </td>
            </tr>
          )}
        </tbody>
      </table>
    );
  }

  static renderCoord2regioncode(documents) {
    return (
      <table className='table table-striped' aria-labelledby="tabelLabel">
        <tbody>
          {documents.map(document =>
            <tr>
              <td>
                <p>{document.address_name}</p>
                <p>x: {document.x} / y: {document.y}</p>
              </td>
            </tr>
          )}
        </tbody>
      </table>
    );
  }  

  render() {
    let contents = this.state.loading ? <div><Spinner animation="border" role="status"><span className="sr-only">Loading...</span></Spinner></div>
      : AddressSearch.renderForecastsTable(this.state.data.documents);
    let coord2regioncode = this.state.coord2regioncode.loading ? <div><Spinner animation="border" role="status"><span className="sr-only">Loading...</span></Spinner></div>
      : AddressSearch.renderCoord2regioncode(this.state.coord2regioncode.data.documents);

    return (
      <div>
        <h1>주소 검색</h1>
        <p>curl -v -X GET "https://dapi.kakao.com/v2/local/search/address.json" \
        --data-urlencode "query=전북 삼성동 100" \
-H "Authorization: KakaoAK REST_API_KEY"</p>
        {contents}
        <h2>좌표로 행정구역정보 받기</h2>
        <p>curl -v -X GET "https://dapi.kakao.com/v2/local/geo/coord2regioncode.json?x=127.1086228&amp;y=37.4012191" \
-H "Authorization: KakaoAK REST_API_KEY"</p>
        {coord2regioncode}
      </div>
    );
  }
  async populateWeatherData(q) {
    const response = await fetch('/api/kakao/addressSearch/address?query=' + q);
    const data = await response.json();
    this.setState({ query: q, data: data, loading: false });
  }
  async renderCoord2regioncode(x, y) {
    const response = await fetch('/api/kakao/addressSearch/coord2regioncode?x=' + x + '&y=' + y);
    const data = await response.json();
    this.state.setCoord2regioncode({ x: x, y: y, data: data, loading: false });
    let coord2regioncode = { x: x, y: y, data: data, loading: false };
    this.setState({ coord2regioncode: coord2regioncode });
  }
}
